const culaMap = {
  "1": "UMNO @ BN",
  "10": "PPBM",
  "11": "GERAKAN",
  "12": "PEJUANG",
  "13": "MCA",
  "14": "MIC",
  "15": "PUTRA",
  "16": "MUDA",
  "1A": "UMNO - SASARAN / LEMAH / ATAS PAGAR",
  "1B": "UMNO SOKONG PAS @ PN",
  "1P": "UMNO SOKONG PN (TIDAK SOKONG PAS)",
  "2": "PAS @ P",
  "3": "PAS LUAR KAWASAN",
  "3B": "PAS LUAR KEDAH (BORNEO)",
  "3D": "PAS LUAR DUN",
  "3K": "PAS LUAR KEDAH (SEMENANJUNG)",
  "3M": "PAS LUAR MALAYSIA",
  "3P": "PAS LUAR PARLIMEN",
  "3U": "PAS LUAR UDM",
  "4": "ATAS PAGAR",
  "4P": "ATAS PAGAR SOKONG PN",
  "5": "PKR @ PH",
  "6": "DHPP",
  "7": "TIDAK DIKENALI",
  "7P": "TIDAK DIKENALI (POLIS / TENTERA)",
  "8": "MATI @ MENINGGAL",
  "9": "PAN @ DAP",
  "97": "LAIN-LAIN BANGSA",
  "98": "INDIA",
  "99": "CINA"
};

const input = $('If').first().json.pages[0].markdown;

// Pisahkan ikut baris table
const lines = input.split("\n").filter(l => l.includes("|") && !l.includes("---"));

const results = [];

for (let line of lines) {
  const parts = line.split("|").map(p => p.trim());
  if (!parts[1] || !parts[2]) continue; // skip header kosong

  const no = parts[1];
  const no_kp = parts[2];
  const nama = parts[3];
  let culaRaw = parts[4] || "";
  // const numPart = parts[5] || "";
  let alamat = parts[5] || "";
  // let alamat = parts.slice(6).join(" ").trim();

  // Combine kalau code & nombor asing (contoh "H" | "1")
  if (culaRaw && !alamat) {
    culaRaw = culaRaw.trim();
    alamat = alamat.trim();
  }

  // Cleaning cula
  let cula = culaRaw.replace("*","").trim();

  // Kalau pattern "H 1" atau "N 1"
  // if (/^[HN]\s*\d+/.test(cula)) {
  //   cula = cula.replace(/^[HN]\s*/, "").trim();
  // }

  // if (cula === "H") cula = "1";
  // if (cula === "N") cula = "2";
  if (cula.toUpperCase() === "PN") cula = "1B";

  if (nama !== "Nama Pemilih" && no_kp !== "No. K/P (Baru)" && cula!="") {
    results.push({
      no,
      no_kp,
      nama_pemilih: nama,
      alamat,
      cula// tambah desc kalau ada
    });
  }
}

return results.map(r => ({ json: r }));

